// // This module compares two 4-bit inputs 'a' and 'b'. Output 'lt' is high if 'a' is NOT less than 'b', 'eq' is high if 'a' is NOT equal to 'b', and 'gt' is high if 'a' is NOT greater than 'b'.
module top_module (
    input wire [3:0] a,
    input wire [3:0] b,
    output wire lt,
    output wire eq,
    output wire gt
);

    assign lt = a < b;
    assign eq = a == b;
    assign gt = a > b;

endmodule
